sql:
SELECT user_id, COUNT(style_id) AS TotalStyles
FROM user_styles
GROUP BY user_id;

SELECT style_id, COUNT(*) AS num_guidelines
FROM style_guidelines
GROUP BY style_id;

external_knowledge:
- 'large font sizes' refers to point sizes greater than 12; 
- 'never touched after creation' indicates that the `modified_at` field is NULL; 
- 'upper-case styles' refers to styles with 'UC' capitalization.

